@prefix rr:   <http://www.w3.org/ns/r2rml#> .
@prefix rml:  <http://semweb.mmlab.be/ns/rml#> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ql:   <http://semweb.mmlab.be/ns/ql#> .
@prefix map:  <http://mapping.example.com/> .
@prefix foaf: <http://xmlns.com/foaf/0.1/> .
@prefix ex:   <http://example.com/> .

map:map_person_000
    rml:logicalSource map:source_000 ;
    rr:subjectMap [
        rr:template "http://example.com/{firstname}"
    ] ;
    rr:predicateObjectMap [
        rr:predicate rdf:type ;
        rr:object foaf:Person
    ], [
        rr:predicate ex:name ;
        rr:objectMap [
            rml:reference "firstname" ;
        ]
    ] .

map:source_000
    rml:source "data.json" ;
    rml:referenceFormulation ql:JSONPath ;
    rml:iterator "$.persons[*]" .

@prefix rr:    <http://www.w3.org/ns/r2rml#> .
@prefix rml:   <http://semweb.mmlab.be/ns/rml#> .
@prefix rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs:  <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ql:    <http://semweb.mmlab.be/ns/ql#> .
@prefix map:   <http://mapping.example.com/> .
@prefix foaf:  <http://xmlns.com/foaf/0.1/> .
@prefix schema: <http://schema.org/> .
@prefix ex:    <http://example.com/> .

map:map_person_000
    rml:logicalSource map:source_000 ;
    rr:subjectMap [
        rr:template "http://example.com/person/{firstname}"
    ] ;
    rr:predicateObjectMap [
        rr:predicate rdf:type ;
        rr:object foaf:Person ;
    ], [
        rr:predicate ex:name ;
        rr:objectMap [

            rml:reference "firstname" ;
        ]
    ], [

        rr:predicate ex:likes ;
        rr:objectMap [
            rr:parentTriplesMap map:map_movie_000 ;
            rr:joinCondition [
                rr:child "movie" ;
                rr:parent "slug" ;
            ]
        ]
    ] .

map:map_movie_000

    rml:logicalSource map:source_001 ;
    rr:subjectMap [

        rr:template "http://example.com/movie/{slug}"
    ] ;
    rr:predicateObjectMap [

        rr:predicate rdf:type ;
        rr:object schema:Movie ;
    ], [

        rr:predicate schema:name ;
        rr:objectMap [

            rml:reference "title" ;
        ]
    ], [

        rr:predicate ex:year ;
        rr:objectMap [

            rml:reference "year" ;
        ]
    ] .

map:source_000 rml:iterator "$.persons[*]" ;
    rml:referenceFormulation ql:JSONPath ;
    rml:source "persons.json" .

map:source_001 rml:referenceFormulation ql:CSV ;
    rml:source "movies.csv" .

@prefix rr:        <http://www.w3.org/ns/r2rml#> .
@prefix rml:       <http://semweb.mmlab.be/ns/rml#> .
@prefix rdf:       <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs:      <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ql:        <http://semweb.mmlab.be/ns/ql#> .
@prefix map:       <http://example.com/base#> .
@prefix prov:      <http://www.w3.org/ns/prov#> .
@prefix schema:    <http://schema.org/> .
@prefix prov-said: <http://semweb.datasciencelab.be/ns/prov-said/> .
@prefix ov:        <http://open.vocab.org/terms/> .
@prefix tsioc:     <http://rdfs.org/sioc/types#> .

map:map_emit_000

    rml:logicalSource map:source_000 ;
    rr:subjectMap [

        rr:template "http://coca-cola.com/emit/{id}"
    ] ;
    rr:predicateObjectMap [

        rr:predicate prov:wasGeneratedBy ;
        rr:object prov:Activity
    ], [

        rr:predicate rdf:type ;
        rr:object prov-said:EmitMessage
    ], [

        rr:predicate prov:wasStartedBy ;
        rr:object <http://coca-cola.com/#me>
    ], [

        rr:predicate prov:startedAtTime, prov:endedAtTime ;
        rr:objectMap [

            rml:reference "created_time" ;
        ]
    ] .

map:map_facebook_post_000

    rml:logicalSource map:source_000 ;
    rr:subjectMap [

        rr:template "http://coca-cola.com/facebook/{id}"
    ] ;
    rr:predicateObjectMap [

        rr:predicate rdf:type ;
        rr:object prov:Entity , ov:MicroblogPost , schema:SocialMediaPosting , tsioc:MicroblogPost
    ], [

        rr:predicate prov:label, schema:articleBody ;
        rr:objectMap [

            rml:reference "message" ;
        ]
    ], [

        rr:predicate schema:mainEntityOfPage ;
        rr:objectMap [

            rml:reference "permalink_url" ;
            rr:datatype schema:URL ;
        ]
    ], [

        rr:predicate prov:wasAttributedTo ;
        rr:object <http://coca-cola.com/#me>
    ], [

        rr:predicate prov:wasGeneratedBy ;
        rr:objectMap [

            rr:parentTriplesMap map:map_emit_000 ;
            rr:joinCondition [
                rr:child "id" ;
                rr:parent "id"
            ]
        ]
    ] .

map:source_000

    rml:source "data.json" ;
    rml:referenceFormulation ql:JSONPath ;
    rml:iterator "$.data[*]" .

